// ─── OGL WebGL Gallery ────────────────────────────────────────────────────────
function lerp(a, b, t) { return a + (b - a) * t; }
function debounce(fn, ms) { let t; return (...a) => { clearTimeout(t); t = setTimeout(() => fn(...a), ms); }; }
function getFontSize(font) { const m = font.match(/(\d+)px/); return m ? +m[1] : 30; }

function createTextTexture(gl, text, font = "bold 22px sans-serif", color = "#10b981") {
  const c = document.createElement("canvas"), ctx = c.getContext("2d");
  ctx.font = font;
  const w = Math.ceil(ctx.measureText(text).width) + 36;
  const h = Math.ceil(getFontSize(font) * 1.5) + 16;
  c.width = w; c.height = h;
  ctx.font = font; ctx.fillStyle = color; ctx.textBaseline = "middle"; ctx.textAlign = "center";
  ctx.fillText(text, w / 2, h / 2);
  const tex = new Texture(gl, { generateMipmaps: false });
  tex.image = c;
  return { texture: tex, width: w, height: h };
}

class TitleMesh {
  constructor({ gl, plane, text, textColor, font }) {
    const { texture, width, height } = createTextTexture(gl, text, font, textColor);
    const geo = new Plane(gl);
    const prog = new Program(gl, {
      vertex: `attribute vec3 position;attribute vec2 uv;uniform mat4 modelViewMatrix;uniform mat4 projectionMatrix;varying vec2 vUv;void main(){vUv=uv;gl_Position=projectionMatrix*modelViewMatrix*vec4(position,1.);}`,
      fragment: `precision highp float;uniform sampler2D tMap;varying vec2 vUv;void main(){vec4 c=texture2D(tMap,vUv);if(c.a<.1)discard;gl_FragColor=c;}`,
      uniforms: { tMap: { value: texture } }, transparent: true,
    });
    this.mesh = new Mesh(gl, { geometry: geo, program: prog });
    const th = plane.scale.y * 0.11;
    this.mesh.scale.set(th * (width / height), th, 1);
    this.mesh.position.y = -plane.scale.y * 0.5 - th * 0.65;
    this.mesh.setParent(plane);
  }
}

class MediaItem {
  constructor({ geometry, gl, image, index, length, scene, screen, text, viewport, bend, textColor, borderRadius, font }) {
    Object.assign(this, { geometry, gl, image, index, length, scene, screen, text, viewport, bend, textColor, borderRadius, font });
    this.extra = 0; this.speed = 0;
    this._initShader(); this._initMesh(); this._initTitle(); this.onResize();
  }
  _initShader() {
    const tex = new Texture(this.gl, { generateMipmaps: true });
    this.program = new Program(this.gl, {
      depthTest: false, depthWrite: false,
      vertex: `precision highp float;attribute vec3 position;attribute vec2 uv;uniform mat4 modelViewMatrix;uniform mat4 projectionMatrix;uniform float uTime;uniform float uSpeed;varying vec2 vUv;void main(){vUv=uv;vec3 p=position;p.z=(sin(p.x*4.+uTime)*1.5+cos(p.y*2.+uTime)*1.5)*(.1+uSpeed*.5);gl_Position=projectionMatrix*modelViewMatrix*vec4(p,1.);}`,
      fragment: `precision highp float;uniform vec2 uImgSz;uniform vec2 uPlnSz;uniform sampler2D tMap;uniform float uBR;varying vec2 vUv;float rBox(vec2 p,vec2 b,float r){vec2 d=abs(p)-b;return length(max(d,vec2(0.)))+min(max(d.x,d.y),0.)-r;}void main(){vec2 ratio=vec2(min((uPlnSz.x/uPlnSz.y)/(uImgSz.x/uImgSz.y),1.),min((uPlnSz.y/uPlnSz.x)/(uImgSz.y/uImgSz.x),1.));vec2 uv=vec2(vUv.x*ratio.x+(1.-ratio.x)*.5,vUv.y*ratio.y+(1.-ratio.y)*.5);vec4 col=texture2D(tMap,uv);float d=rBox(vUv-.5,vec2(.5-uBR),uBR);gl_FragColor=vec4(col.rgb,1.-smoothstep(-.002,.002,d));}`,
      uniforms: { tMap:{value:tex}, uPlnSz:{value:[0,0]}, uImgSz:{value:[0,0]}, uSpeed:{value:0}, uTime:{value:Math.random()*100}, uBR:{value:this.borderRadius} },
      transparent: true,
    });
    const img = new Image(); img.crossOrigin = "anonymous"; img.src = this.image;
    img.onload = () => { tex.image = img; this.program.uniforms.uImgSz.value = [img.naturalWidth, img.naturalHeight]; };
  }
  _initMesh() { this.plane = new Mesh(this.gl, { geometry: this.geometry, program: this.program }); this.plane.setParent(this.scene); }
  _initTitle() { new TitleMesh({ gl: this.gl, plane: this.plane, text: this.text, textColor: this.textColor, font: this.font }); }
  update(scroll, dir) {
    this.plane.position.x = this.x - scroll.current - this.extra;
    const x = this.plane.position.x, H = this.viewport.width / 2;
    if (!this.bend) { this.plane.position.y = 0; this.plane.rotation.z = 0; }
    else {
      const B = Math.abs(this.bend), R = (H*H + B*B) / (2*B), ex = Math.min(Math.abs(x), H);
      this.plane.position.y = this.bend > 0 ? -(R - Math.sqrt(Math.max(0,R*R-ex*ex))) : R - Math.sqrt(Math.max(0,R*R-ex*ex));
      this.plane.rotation.z = (this.bend>0?-1:1)*Math.sign(x)*Math.asin(Math.min(ex/R,1));
    }
    this.speed = scroll.current - scroll.last;
    this.program.uniforms.uTime.value += 0.04;
    this.program.uniforms.uSpeed.value = this.speed;
    const po = this.plane.scale.x / 2, vo = this.viewport.width / 2;
    if (dir === "right" && this.plane.position.x + po < -vo) this.extra -= this.widthTotal;
    if (dir === "left"  && this.plane.position.x - po >  vo) this.extra += this.widthTotal;
  }
  onResize({ screen, viewport } = {}) {
    if (screen) this.screen = screen;
    if (viewport) this.viewport = viewport;
    const sc = this.screen.height / 1500;
    this.plane.scale.y = this.viewport.height * (900*sc) / this.screen.height;
    this.plane.scale.x = this.viewport.width  * (700*sc) / this.screen.width;
    this.program.uniforms.uPlnSz.value = [this.plane.scale.x, this.plane.scale.y];
    this.width = this.plane.scale.x + 2;
    this.widthTotal = this.width * this.length;
    this.x = this.width * this.index;
  }
}

class GalleryCore {
  constructor(el, { items=[], bend=3, textColor="#10b981", borderRadius=0.1, font="bold 20px sans-serif", scrollSpeed=2, scrollEase=0.05 }) {
    this.el = el; this.scrollSpeed = scrollSpeed;
    this.scroll = { ease: scrollEase, current: 0, target: 0, last: 0 };
    this._checkDebounce = debounce(() => this._snap(), 200);
    this.isDown = false; this.startX = 0; this.medias = [];
    this._initRenderer(); this._initCamera(); this.scene = new Transform();
    this._resize(); this.geo = new Plane(this.gl, { heightSegments:50, widthSegments:100 });
    const doubled = [...items, ...items];
    this.medias = doubled.map((d,i) => new MediaItem({ geometry:this.geo, gl:this.gl, image:d.image, index:i, length:doubled.length, scene:this.scene, screen:this.screen, text:d.text, viewport:this.vp, bend, textColor, borderRadius, font }));
    this._loop(); this._events();
  }
  _initRenderer() {
    this.renderer = new Renderer({ alpha:true, antialias:true, dpr:Math.min(devicePixelRatio||1,2) });
    this.gl = this.renderer.gl; this.gl.clearColor(0,0,0,0);
    this.el.appendChild(this.renderer.gl.canvas);
  }
  _initCamera() { this.camera = new Camera(this.gl); this.camera.fov=45; this.camera.position.z=20; }
  _resize() {
    this.screen = { width:this.el.clientWidth, height:this.el.clientHeight };
    this.renderer.setSize(this.screen.width, this.screen.height);
    this.camera.perspective({ aspect:this.screen.width/this.screen.height });
    const h = 2*Math.tan(this.camera.fov*Math.PI/360)*20;
    this.vp = { width:h*this.camera.aspect, height:h };
    this.medias?.forEach(m => m.onResize({ screen:this.screen, viewport:this.vp }));
  }
  _snap() { if (!this.medias[0]) return; const w=this.medias[0].width; const i=Math.round(Math.abs(this.scroll.target)/w); this.scroll.target = this.scroll.target<0?-(w*i):w*i; }
  _loop() {
    this.scroll.current = lerp(this.scroll.current, this.scroll.target, this.scroll.ease);
    const dir = this.scroll.current > this.scroll.last ? "right" : "left";
    this.medias.forEach(m => m.update(this.scroll, dir));
    this.renderer.render({ scene:this.scene, camera:this.camera });
    this.scroll.last = this.scroll.current;
    this.raf = requestAnimationFrame(() => this._loop());
  }
  _events() {
    this._onR = () => this._resize();
    this._onW = (e) => { this.scroll.target += (e.deltaY>0?this.scrollSpeed:-this.scrollSpeed)*0.2; this._checkDebounce(); };
    this._onD = (e) => { this.isDown=true; this.scroll.pos=this.scroll.current; this.startX="touches"in e?e.touches[0].clientX:e.clientX; };
    this._onM = (e) => { if(!this.isDown)return; const x="touches"in e?e.touches[0].clientX:e.clientX; this.scroll.target=(this.scroll.pos??0)+(this.startX-x)*this.scrollSpeed*0.025; };
    this._onU = () => { this.isDown=false; this._snap(); };
    window.addEventListener("resize",this._onR);
    window.addEventListener("wheel",this._onW,{passive:true});
    window.addEventListener("mousedown",this._onD); window.addEventListener("mousemove",this._onM); window.addEventListener("mouseup",this._onU);
    window.addEventListener("touchstart",this._onD,{passive:true}); window.addEventListener("touchmove",this._onM,{passive:true}); window.addEventListener("touchend",this._onU);
  }
  destroy() {
    cancelAnimationFrame(this.raf);
    window.removeEventListener("resize",this._onR); window.removeEventListener("wheel",this._onW);
    window.removeEventListener("mousedown",this._onD); window.removeEventListener("mousemove",this._onM); window.removeEventListener("mouseup",this._onU);
    window.removeEventListener("touchstart",this._onD); window.removeEventListener("touchmove",this._onM); window.removeEventListener("touchend",this._onU);
    this.renderer?.gl?.canvas?.parentNode?.removeChild(this.renderer.gl.canvas);
  }
}

function CircularGallery(props) {
  const ref = useRef(null);
  useEffect(() => {
    if (!ref.current) return;
    const g = new GalleryCore(ref.current, props);
    return () => g.destroy();
  }, []);
  return <div ref={ref} style={{width:"100%",height:"100%",overflow:"hidden",cursor:"grab"}} />;
}

// ─── Hooks ────────────────────────────────────────────────────────────────────
function useCountUp(target, dur=2200, go=false) {
  const [n, set] = useState(0);
  useEffect(() => {
    if (!go) return;
    let s=null;
    const step = ts => { if(!s) s=ts; const p=Math.min((ts-s)/dur,1); set(Math.floor((1-Math.pow(1-p,3))*target)); if(p<1) requestAnimationFrame(step); };
    requestAnimationFrame(step);
  }, [go]);
  return n;
}
function useInView(thresh=0.15) {
  const ref=useRef(null); const [v,set]=useState(false);
  useEffect(()=>{ const o=new IntersectionObserver(([e])=>{ if(e.isIntersecting){set(true);o.disconnect();} },{threshold:thresh}); if(ref.current) o.observe(ref.current); return()=>o.disconnect(); },[]);
  return [ref,v];
}

