// ─── Particle Background ──────────────────────────────────────────────────────
function Particles() {
  const ref = useRef(null);
  useEffect(() => {
    const c = ref.current; if(!c) return;
    const ctx = c.getContext("2d");
    let raf;
    const resize = () => { c.width=innerWidth; c.height=innerHeight; };
    resize(); window.addEventListener("resize", resize);
    const pts = Array.from({length:50}, () => ({
      x:Math.random()*c.width, y:Math.random()*c.height,
      r:Math.random()*1.2+0.3, dx:(Math.random()-.5)*.28, dy:(Math.random()-.5)*.28,
      o:Math.random()*.3+.04,
    }));
    const draw = () => {
      ctx.clearRect(0,0,c.width,c.height);
      pts.forEach(p => {
        p.x+=p.dx; p.y+=p.dy;
        if(p.x<0)p.x=c.width; if(p.x>c.width)p.x=0;
        if(p.y<0)p.y=c.height; if(p.y>c.height)p.y=0;
        ctx.beginPath(); ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
        ctx.fillStyle=`rgba(16,185,129,${p.o})`; ctx.fill();
      });
      pts.forEach((a,i) => pts.slice(i+1).forEach(b => {
        const d=Math.hypot(a.x-b.x,a.y-b.y);
        if(d<120){ ctx.beginPath(); ctx.moveTo(a.x,a.y); ctx.lineTo(b.x,b.y); ctx.strokeStyle=`rgba(16,185,129,${.07*(1-d/120)})`; ctx.lineWidth=.5; ctx.stroke(); }
      }));
      raf=requestAnimationFrame(draw);
    };
    draw();
    return () => { cancelAnimationFrame(raf); window.removeEventListener("resize",resize); };
  },[]);
  return <canvas ref={ref} style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:0}} />;
}

// ─── Custom Cursor ────────────────────────────────────────────────────────────
function Cursor() {
  const dot=useRef(null), ring=useRef(null);
  const pos=useRef({x:0,y:0}), lag=useRef({x:0,y:0});
  const [vis,setVis]=useState(false), [hot,setHot]=useState(false), [tap,setTap]=useState(false);
  const raf=useRef(null);
  useEffect(()=>{
    const mv=e=>{ pos.current={x:e.clientX,y:e.clientY}; setVis(true);
      const el=document.elementFromPoint(e.clientX,e.clientY);
      setHot(!!(el&&(el.closest("a")||el.closest("button")||el.closest("[data-c]")))); };
    const dn=()=>setTap(true), up=()=>setTap(false);
    const loop=()=>{ lag.current.x=lerp(lag.current.x,pos.current.x,.11); lag.current.y=lerp(lag.current.y,pos.current.y,.11);
      if(ring.current){ring.current.style.left=lag.current.x+"px";ring.current.style.top=lag.current.y+"px";}
      if(dot.current){dot.current.style.left=pos.current.x+"px";dot.current.style.top=pos.current.y+"px";}
      raf.current=requestAnimationFrame(loop); };
    raf.current=requestAnimationFrame(loop);
    window.addEventListener("mousemove",mv); window.addEventListener("mousedown",dn); window.addEventListener("mouseup",up);
    document.documentElement.addEventListener("mouseleave",()=>setVis(false));
    return()=>{ cancelAnimationFrame(raf.current); window.removeEventListener("mousemove",mv); window.removeEventListener("mousedown",dn); window.removeEventListener("mouseup",up); };
  },[]);
  const ds=tap?5:8, rs=hot?50:tap?16:34;
  return(<>
    <div ref={dot} style={{position:"fixed",pointerEvents:"none",zIndex:9999,width:ds,height:ds,borderRadius:"50%",background:"#10b981",transform:"translate(-50%,-50%)",transition:"width .1s,height .1s",opacity:vis?1:0,mixBlendMode:"difference"}}/>
    <div ref={ring} style={{position:"fixed",pointerEvents:"none",zIndex:9998,width:rs,height:rs,borderRadius:"50%",border:`1.5px solid rgba(16,185,129,${hot?.9:.5})`,transform:"translate(-50%,-50%)",transition:"width .3s cubic-bezier(.16,1,.3,1),height .3s cubic-bezier(.16,1,.3,1),opacity .3s",opacity:vis?1:0,background:hot?"rgba(16,185,129,.05)":"transparent"}}/>
  </>);
}

