// ─── Spotlight Card ───────────────────────────────────────────────────────────
function SC({children, style={}, onClick}) {
  const r=useRef(null);
  const mm=e=>{ const rc=r.current?.getBoundingClientRect(); if(!rc)return; r.current.style.setProperty("--mx",`${e.clientX-rc.left}px`); r.current.style.setProperty("--my",`${e.clientY-rc.top}px`); };
  return <div ref={r} onMouseMove={mm} onClick={onClick} data-c="" style={style} className="SC">{children}</div>;
}

